      tokenIn: ETH_ADDRESS,
      tokenOut: USDC_ARBITRUM,
      tokenInChainId: String(CHAIN_ID),
      tokenOutChainId: String(CHAIN_ID),
      amount: AMOUNT_IN.toString(),
      type: 'EXACT_INPUT',
      slippageTolerance: 0.5,
      routingPreference: 'BEST_PRICE',
    }),
  });

  const quoteResponse = await quoteRes.json();
  if (!quoteRes.ok) throw new Error(`Quote failed: ${quoteResponse.detail || quoteRes.status}`);

  // Display quote details — shape differs by routing type
  const routing = quoteResponse.routing;
  console.log(`   Routing: ${routing}`);

  if (routing === 'DUTCH_V2' || routing === 'DUTCH_V3' || routing === 'PRIORITY') {
    // UniswapX: output is in orderInfo.outputs[0]
