    if (output) {
      const usdcOut = formatUnits(BigInt(output.startAmount), 6);
      const usdcFloor = formatUnits(BigInt(output.endAmount), 6);
      console.log(`   USDC out (best case): ${usdcOut}`);
      console.log(`   USDC out (floor):     ${usdcFloor}`);
      console.log(`   Gas: free (UniswapX — fillers pay gas)\n`);
